module RefModule(
  //------------------------------
  // Top level control signals
  //------------------------------
  input wire clk,
  //------------------------------
  // Input ctrl
  //------------------------------
  input  wire [2:0]       rd_at,
  input  wire [2:0]       wr_at,
  input  wire             wr_en,
  input  wire [31:0]      din,
  //------------------------------
  // Output ctrl
  //------------------------------
  output wire [31:0]      dout
);reg [31:0] ctrl [2:0];

  always @(posedge clk)
  begin
    if (wr_en == 1'b1)
      ctrl[wr_at] <= din;
  end

  assign dout = ctrl[rd_at];

endmodule
